public class OrderListViewModel
{
    public List<Order> Orders { get; set; }

    public OrderListViewModel(IOrderService service)
    {
        Orders = service.GetOrders(); // 约 3000 条
        service.OrderUpdated += OnOrderUpdated;
    }

    private void OnOrderUpdated(object sender, OrderEventArgs e)
    {
        var order = Orders.FirstOrDefault(o => o.Id == e.OrderId);
        if (order != null) RefreshUI();
    }
}
