public class ProductListViewModel : IDisposable
{
    public ObservableCollection<Product> Products { get; } = new();
    private static readonly Brush _highlightBrush;

    static ProductListViewModel()
    {
        _highlightBrush = new SolidColorBrush(Colors.Orange);
        _highlightBrush.Freeze();
    }

    public ProductListViewModel(IProductService service)
    {
        service.ProductChanged += OnProductChanged;
        _service = service;
    }

    public void Dispose() => _service.ProductChanged -= OnProductChanged;
    private void OnProductChanged(object sender, EventArgs e) { }
    private readonly IProductService _service;
}
```

